namespace RecipeHub.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = [];
    public List<string> Steps { get; set; } = [];
    public List<int> Ratings { get; set; } = [];

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes =
    [
        new()
        {
            Id = 1,
            Title = "Classic Margherita Pizza",
            Category = "Italian",
            Ingredients = ["Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt"],
            Steps = ["Preheat oven to 475°F.", "Roll out dough on floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and drizzle olive oil."],
            Ratings = [5, 4, 5, 4, 5]
        },
        new()
        {
            Id = 2,
            Title = "Chicken Tikka Masala",
            Category = "Indian",
            Ingredients = ["Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger"],
            Steps = ["Marinate chicken in yogurt and spices for 2 hours.", "Grill or pan-sear chicken until charred.", "Sauté onions, garlic, and ginger.", "Add tomato sauce and simmer 15 minutes.", "Stir in cream and cooked chicken.", "Serve over basmati rice."],
            Ratings = [5, 5, 4, 5]
        },
        new()
        {
            Id = 3,
            Title = "Beef Tacos",
            Category = "Mexican",
            Ingredients = ["Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning"],
            Steps = ["Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm taco shells in oven.", "Assemble tacos with beef and toppings.", "Serve with salsa and sour cream."],
            Ratings = [4, 4, 3, 5, 4]
        },
        new()
        {
            Id = 4,
            Title = "Pad Thai",
            Category = "Thai",
            Ingredients = ["Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Lime"],
            Steps = ["Soak rice noodles in warm water 30 minutes.", "Stir-fry shrimp until pink, set aside.", "Scramble eggs in the same wok.", "Add noodles, tamarind paste, and fish sauce.", "Toss with shrimp, bean sprouts, and green onions.", "Serve with crushed peanuts and lime wedges."],
            Ratings = [5, 4, 5]
        },
        new()
        {
            Id = 5,
            Title = "Chocolate Lava Cake",
            Category = "Desserts",
            Ingredients = ["Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract"],
            Steps = ["Preheat oven to 425°F.", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold chocolate mixture into eggs, add flour.", "Pour into greased ramekins.", "Bake 12-14 minutes until edges are set but center jiggles."],
            Ratings = [5, 5, 5, 4, 5]
        },
        new()
        {
            Id = 6,
            Title = "Caesar Salad",
            Category = "Salads",
            Ingredients = ["Romaine lettuce", "Parmesan cheese", "Croutons", "Caesar dressing", "Lemon juice", "Anchovy paste"],
            Steps = ["Wash and chop romaine lettuce.", "Make dressing: mix anchovy paste, lemon juice, garlic, and olive oil.", "Toss lettuce with dressing.", "Top with shaved parmesan and croutons.", "Serve immediately."],
            Ratings = [4, 3, 4, 4]
        }
    ];

    private int _nextId = 7;

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetRecipesByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetRecipeById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int rating)
    {
        var recipe = GetRecipeById(recipeId);
        if (recipe is not null && rating is >= 1 and <= 5)
        {
            recipe.Ratings.Add(rating);
        }
    }

    public void AddRecipe(string title, string category, List<string> ingredients, List<string> steps)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        });
    }
}

