arguments.file_text:
@page "/recipes"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>Browse Recipes - RecipeHub</PageTitle>

<h1>Browse Recipes</h1>
<p>Select a category to explore recipes.</p>

<div class="list-group">
    @foreach (var category in RecipeService.GetCategories())
    {
        <a href="recipes/@category" class="list-group-item list-group-item-action d-flex justify-content-between align-items-center">
            @category
            <span class="badge bg-primary rounded-pill">@RecipeService.GetRecipesByCategory(category).Count</span>
        </a>
    }
</div>

@page "/recipes/{Category}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@Category Recipes - RecipeHub</PageTitle>

<h1>@Category Recipes</h1>
<nav aria-label="breadcrumb">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
        <li class="breadcrumb-item active">@Category</li>
    </ol>
</nav>

@if (recipes.Count == 0)
{
    <p>No recipes found in this category.</p>
}
else
{
    <div class="row">
        @foreach (var recipe in recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <p class="card-text text-muted">
                            @if (recipe.AverageRating > 0)
                            {
                                <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.Ratings.Count ratings)</span>
                            }
                            else
                            {
                                <span>No ratings yet</span>
                            }
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    [Parameter]
    public string Category { get; set; } = string.Empty;

    private List<RecipeHub.Models.Recipe> recipes = [];

    protected override void OnParametersSet()
    {
        recipes = RecipeService.GetRecipesByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@inject RecipeHub.Services.RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeHub</PageTitle>

@if (recipe is null)
{
    <p>Recipe not found.</p>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="recipes">All Categories</a></li>
            <li class="breadcrumb-item"><a href="recipes/@recipe.Category">@recipe.Category</a></li>
            <li class="breadcrumb-item active">@recipe.Title</li>
        </ol>
    </nav>

    <h1>@recipe.Title</h1>
    <p class="text-muted">Category: @recipe.Category</p>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <hr />
    <h3>Rate this Recipe</h3>
    <StarRating RecipeId="recipe.Id" CurrentAverage="recipe.AverageRating" TotalRatings="recipe.Ratings.Count" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeHub.Models.Recipe? recipe;

    protected override void OnParametersSet()
    {
        recipe = RecipeService.GetRecipeById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService

<div class="d-flex align-items-center gap-3">
    <div class="star-rating" style="font-size: 1.5rem; cursor: pointer;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span @onclick="() => SubmitRating(star)"
                  @onmouseover="() => hoverRating = star"
                  @onmouseout="() => hoverRating = 0"
                  style="color: @(GetStarColor(star))">
                ★
            </span>
        }
    </div>
    <span class="text-muted">
        @if (submitted)
        {
            <span class="text-success">Thanks for rating!</span>
        }
        else if (CurrentAverage > 0)
        {
            <span>⭐ @CurrentAverage.ToString("F1") (@TotalRatings ratings)</span>
        }
        else
        {
            <span>Be the first to rate!</span>
        }
    </span>
</div>

@code {
    [Parameter] public int RecipeId { get; set; }
    [Parameter] public double CurrentAverage { get; set; }
    [Parameter] public int TotalRatings { get; set; }

    private int hoverRating;
    private int selectedRating;
    private bool submitted;

    private string GetStarColor(int star)
    {
        if (hoverRating >= star) return "#ffc107";
        if (selectedRating >= star) return "#ffc107";
        return "#dee2e6";
    }

    private void SubmitRating(int rating)
    {
        selectedRating = rating;
        RecipeService.AddRating(RecipeId, rating);
        var recipe = RecipeService.GetRecipeById(RecipeId);
        if (recipe is not null)
        {
            CurrentAverage = recipe.AverageRating;
            TotalRatings = recipe.Ratings.Count;
        }
        submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeHub.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage is not null)
{
    <div class="alert alert-success">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="model.Title" placeholder="e.g., Grandma's Apple Pie" />
        <ValidationMessage For="() => model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputText id="category" class="form-control" @bind-Value="model.Category" placeholder="e.g., Desserts, Italian, Mexican" />
        <ValidationMessage For="() => model.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="model.IngredientsText" placeholder="1 cup flour&#10;2 eggs&#10;1/2 cup sugar" />
        <ValidationMessage For="() => model.IngredientsText" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="model.StepsText" placeholder="Preheat oven to 350°F.&#10;Mix dry ingredients.&#10;Add wet ingredients and stir." />
        <ValidationMessage For="() => model.StepsText" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        var ingredients = model.IngredientsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        var steps = model.StepsText
            .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
            .ToList();

        RecipeService.AddRecipe(model.Title, model.Category, ingredients, steps);
        successMessage = $"Recipe \"{model.Title}\" submitted successfully!";
        model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient.")]
        public string IngredientsText { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step.")]
        public string StepsText { get; set; } = string.Empty;
    }
}

